import { createSignal, createRoot, JSX, createUniqueId } from 'solid-js';
import type { ToastData, ToastOptions, ToastType, ToastPosition, Message } from './toast.type';

// Default values
const DEFAULT_DURATION: Record<ToastType, number> = {
  blank: 3000,
  success: 3000,
  error: 3000,
  info: 3000,
  warning: 3000,
  loading: Infinity,
  custom: 3000,
};

const DEFAULT_POSITION: ToastPosition = 'top-right';
const DEFAULT_UNMOUNT_DELAY = 400;
const MAX_TOASTS = 10;

// Toast store using signals
function createToastStore() {
  const [toasts, setToasts] = createSignal<ToastData[]>([]);
  const [pausedAt, setPausedAt] = createSignal<number | null>(null);

  const createToast = (
    message: Message | ((toast: ToastData) => JSX.Element),
    type: ToastType,
    options?: ToastOptions,
  ): ToastData => {
    const id = createUniqueId();
    const existingToast = toasts().find(t => t.id === id);
    const toast: ToastData = {
      id,
      type,
      message: message as Message,
      icon: options?.icon,
      duration: options?.duration ?? DEFAULT_DURATION[type],
      pauseDuration: existingToast?.pauseDuration ?? 0,
      paused: false,
      position: options?.position ?? DEFAULT_POSITION,
      ariaProps: options?.ariaProps ?? {
        role: 'status',
        'aria-live': 'polite',
      },
      style: options?.style,
      class: options?.class,
      iconTheme: options?.iconTheme,
      createdAt: existingToast?.createdAt ?? Date.now(),
      visible: true,
      unmountDelay: options?.unmountDelay ?? DEFAULT_UNMOUNT_DELAY,
      canPause: options?.canPause ?? true,
      showCloseIcon: options?.showCloseIcon ?? true,
    };

    return toast;
  };

  const upsertToast = (toast: ToastData) => {
    setToasts(prev => {
      const index = prev.findIndex(t => t.id === toast.id);
      if (index !== -1) {
        // Update existing toast
        const newToasts = [...prev];
        newToasts[index] = { ...prev[index], ...toast, updatedAt: Date.now() };
        return newToasts;
      } else {
        // Add new toast at the beginning and enforce max limit
        let newToasts = [toast, ...prev];
        if (newToasts.length > MAX_TOASTS) {
          newToasts = newToasts.slice(0, MAX_TOASTS);
        }
        return newToasts;
      }
    });
  };

  const dismissToast = (toastId?: string) => {
    setToasts(prev => {
      if (toastId) {
        return prev.map(t => (t.id === toastId ? { ...t, visible: false } : t));
      } else {
        // Dismiss all
        return prev.map(t => ({ ...t, visible: false }));
      }
    });
  };

  const removeToast = (toastId?: string) => {
    setToasts(prev => {
      if (toastId) {
        return prev.filter(t => t.id !== toastId);
      } else {
        // Remove all
        return [];
      }
    });
  };

  const dismissPop = () => {
    setToasts(prev => {
      for (let i = prev.length - 1; i >= 0; i--) {
        if (prev[i].visible) {
          return prev.map((t, idx) => (idx === i ? { ...t, visible: false } : t));
        }
      }
      return prev;
    });
  };

  const removePop = () => {
    setToasts(prev => {
      for (let i = prev.length - 1; i >= 0; i--) {
        if (prev[i].visible) {
          return [...prev.slice(0, i), ...prev.slice(i + 1)];
        }
      }
      return prev;
    });
  };

  const dismissShift = () => {
    setToasts(prev => {
      for (let i = 0; i < prev.length; i++) {
        if (prev[i].visible) {
          return prev.map((t, idx) => (idx === i ? { ...t, visible: false } : t));
        }
      }
      return prev;
    });
  };

  const removeShift = () => {
    setToasts(prev => {
      for (let i = 0; i < prev.length; i++) {
        if (prev[i].visible) {
          return [...prev.slice(0, i), ...prev.slice(i + 1)];
        }
      }
      return prev;
    });
  };

  const updateToast = (toastId: string, updates: Partial<ToastData>) => {
    setToasts(prev =>
      prev.map(t => (t.id === toastId ? { ...t, ...updates, updatedAt: Date.now() } : t)),
    );
  };

  const pauseToast = (toastId: string) => {
    setToasts(prev => prev.map(t => (t.id === toastId && !t.paused ? { ...t, paused: true } : t)));
    setPausedAt(Date.now());
  };

  const resumeToast = (toastId: string) => {
    const pauseTime = pausedAt();
    if (pauseTime) {
      setToasts(prev =>
        prev.map(t =>
          t.id === toastId && t.paused
            ? { ...t, paused: false, pauseDuration: t.pauseDuration + (Date.now() - pauseTime) }
            : t,
        ),
      );
    }
    setPausedAt(null);
  };

  return {
    toasts,
    createToast,
    upsertToast,
    dismissToast,
    removeToast,
    updateToast,
    pauseToast,
    resumeToast,
    dismissPop,
    removePop,
    dismissShift,
    removeShift,
  };
}

// Create singleton store
export const toastStore = createRoot(createToastStore);
